    CalendarView.prototype.firstYearOfDecade = function(date) {

     //MomentUtil.tz(moment(), this.timeZone()).month()+1
      var currentYear, firstYear, offset, year;
	  

      currentYear = MomentUtil.tz(moment(), this.timeZone()).year();
	   firstYear = currentYear;
     	  if(this.startMonthOfFicalYear() === 4)
		  {
			  if(MomentUtil.tz(moment(), this.timeZone()).month() < 3)
			  {
				        firstYear = currentYear -1;
			  }
		  }else if(this.startMonthOfFicalYear() === 7)
		  {
			   if(MomentUtil.tz(moment(), this.timeZone()).month() < 6)
			  {
				        firstYear = currentYear -1;
			  }
		  }
	 
      
	  //console.log(firstYear + ' ::::: ' + date.year())
	  
      offset = Math.floor((date.year() - firstYear) / 9);
   
      year = firstYear + offset * 9;
   
      
      return MomentUtil.tz([year], this.timeZone());
    };

    CalendarView.prototype.firstYearOfFinacial = function(date) {

   
      var currentYear, firstYear, offset, year;
      currentYear = MomentUtil.tz(moment(), this.timeZone()).year();
	 
      firstYear = currentYear - 4;
    
      offset = Math.floor((date.year() - firstYear) / 1);
   
      year = firstYear + offset * 1;
    
      
      return MomentUtil.tz([year], this.timeZone());
    };

